const { SQSClient, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
// Assuming you have your credentials in environment variables or AWS config file
const sqs = new SQSClient({ region: "REGION" }); // replace REGION with your aws region

async function processMessages(queueUrl) {
    try {
        const messages = await sqs.receiveMessage({ QueueUrl: queueUrl, MaxNumberOfMessages: 10 },
            (err, data) => {
                if (err) console.log("Error", err);
                else return data;
            });
        
        for(let i=0; i<messages.Messages.length; i++){
            // Here you should have your logic to process the financial transactions based on message content
            
            const deleteParams = {
                QueueUrl: queueUrl,
                ReceiptHandle: messages.Messages[i].ReceiptHandle
            };
        
            try{
                await sqs.send(new DeleteMessageCommand(deleteParams));
                console.log("Message deleted successfully");
            } catch (err) {
                console.error('Error deleting message from queue', err);
            }
        }
    } catch (err) {
        console.log("Receive error", err);
    }
}